/// <summary>
/// Extension class of class <c>InventMovement</c> for accusation.
/// </summary>
[ExtensionOf(classStr(InventMovement))]
final class FWFAccusInventMovement_Extension
{
    private boolean isCreditNoteAccusMode;
    private AmountCur newCostAmountMST;

}

Method.Source:
/// <summary>
/// Returns the current InventType.
/// </summary>
/// <returns>The <c>InventType</c> object.</returns>
public InventType FWFgetInventType()
{
    return inventType;
}

protected boolean performFinancialLedgerUpdate(LedgerVoucher _ledgerVoucher, InventTrans _inventTrans, InventUpdate _updateNow, InventOnhand _inventOnhand, InventTrans _inventTransUpd_RU)
{
    boolean performOk;

    this.isCreditNoteAccusMode = _updateNow.parmFWFCreditNoteAccusMode();
    this.newCostAmountMST = _updateNow.parmProjCostAmountMST();

    performOk = next performFinancialLedgerUpdate(_ledgerVoucher, _inventTrans, _updateNow, _inventOnhand, _inventTransUpd_RU);

    this.isCreditNoteAccusMode = false;

    return performOk;
}

protected void addLedgerVoucherTransactionAmountsForFinancialUpdate(LedgerVoucher _ledgerVoucher, InventTrans _inventTrans, LedgerVoucherObject _ledgerVoucherObject, CurrencyExchangeHelper _currencyExchHelper, InventTransPosting _inventTransPosting)
{
    InventTrans inventTransLocal = _inventTrans.data();
    if (this.isCreditNoteAccusMode)
    {
        inventTransLocal.CostAmountPhysical = this.newCostAmountMST;
    }

    next addLedgerVoucherTransactionAmountsForFinancialUpdate(_ledgerVoucher, inventTransLocal, _ledgerVoucherObject, _currencyExchHelper, _inventTransPosting);
}
